import { Router } from 'express';
import { prisma } from '../lib/prisma';
import { authenticate } from '../middleware/auth';

export const usersRouter = Router();

usersRouter.get('/', authenticate, async (req, res) => {
  const users = await prisma.user.findMany();
  res.json(users);
});

usersRouter.get('/:id', authenticate, async (req, res) => {
  const user = await prisma.user.findUnique({ where: { id: parseInt(req.params.id) } });
  res.json(user);
});

usersRouter.put('/:id', authenticate, async (req, res) => {
  const user = await prisma.user.update({ where: { id: parseInt(req.params.id) }, data: req.body });
  res.json(user);
});

usersRouter.delete('/:id', authenticate, async (req, res) => {
  await prisma.user.delete({ where: { id: parseInt(req.params.id) } });
  res.json({ deleted: true });
});

