import { Router } from 'express';
import { prisma } from '../lib/prisma';
import { authenticate } from '../middleware/auth';

export const postsRouter = Router();

postsRouter.get('/', async (req, res) => {
  const posts = await prisma.post.findMany({ include: { author: true, tags: true } });
  res.json(posts);
});

postsRouter.get('/:id', async (req, res) => {
  const post = await prisma.post.findUnique({ where: { id: parseInt(req.params.id) }, include: { author: true, tags: true } });
  res.json(post);
});

postsRouter.post('/', authenticate, async (req, res) => {
  const post = await prisma.post.create({ data: { ...req.body, authorId: req.userId } });
  res.status(201).json(post);
});

postsRouter.put('/:id', authenticate, async (req, res) => {
  const post = await prisma.post.update({ where: { id: parseInt(req.params.id) }, data: req.body });
  res.json(post);
});

postsRouter.delete('/:id', authenticate, async (req, res) => {
  await prisma.post.delete({ where: { id: parseInt(req.params.id) } });
  res.json({ deleted: true });
});

